mapper.select:
/* 휴대폰 할부개월 조회 : AppformMapper.selectModelMonthlyList */
SELECT
INST_NOM AS MODEL_MONTHLY
FROM ORG_INST_NOM_MST
WHERE SALE_PLCY_CD = #{modelSalePolicyCode}
GROUP BY INST_NOM

/* 판매정책조회 : MspMapper.findMspSaleOrgnMst */ SELECT PL.SALE_PLCY_CD , --판매정책코드 PL.SALE_PLCY_NM, --판매정책명 PL.SALE_STRT_DTTM, --판매시작일시 PL.SALE_END_DTTM, --판매종료일시 PL.PLCY_TYPE_CD, --정책유형코드 M:오프라인, O:온라인 PL.ORGN_TYPE, --조직유형 PL.PLCY_SCTN_CD, --정책구분코드 01:단말, 02:USIM PL.PRDT_SCTN_CD, --제품구분코 02:3G, 03:LTE PL.APPL_SCTN_CD, --적용구분코드 O:개통일, R:접수일 PL.INST_RATE, --할부이자율 PL.NEW_YN, --신규여부 PL.MNP_YN, --번호이동여부 PL.HCN_YN, --기변여부 PL.HDN_YN, --우수기변여부 PL.CNFM_YN, --확정여부 PL.CNFM_ID, --확정자ID PL.CNFM_DTTM, --확정일시 PL.REGST_ID, --등록자ID PL.REGST_DTTM, --등록일시 PL.RVISN_ID, --수정자ID PL.RVISN_DTTM, --수정일시 PL.SPRT_TP, --할인유형 (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID='F002' AND USE_YN='Y' AND PL.SPRT_TP=DTL_CD) AS SPRT_NM, --할인유형명 ORG.ORGN_ID, --조직 PRDT.PRDT_ID -- 단말아이디 FROM MSP_SALE_PLCY_MST PL, MSP_SALE_ORGN_MST ORG, MSP_SALE_PRDT_MST PRDT WHERE PL.CNFM_YN='Y' -- 결제 YN (필수) AND PL.SALE_PLCY_CD = ORG.SALE_PLCY_CD AND PL.SALE_PLCY_CD = PRDT.SALE_PLCY_CD AND ORG.SALE_PLCY_cD = PRDT.SALE_PLCY_CD AND TO_CHAR(SYSDATE,'yyyymmddhh24miss') BETWEEN PL.SALE_STRT_DTTM AND PL.SALE_END_DTTM --판매기간 (필수) AND PL.PLCY_TYPE_CD = #{plcyTypeCd} -- 온라인:O , 오프라인:M , 직영온라인 : D AND PL.PLCY_SCTN_CD = #{plcySctnCd} -- 01:단말,02:유심 AND ORG.ORGN_ID = #{orgnId} -- 조직코드
AND PL.PRDT_SCTN_CD = #{prdtSctnCd} -- LTE,3G
AND PRDT.PRDT_ID = #{prdtId} -- 단말기ID (자급제인 경우는 SKIP 처리)
AND PL.SPRT_TP = #{sprtTp} -- KD:단말할인,PM:요금할인
AND PL.SALE_PLCY_NM LIKE #{salePlcyNm}
AND PL.SALE_PLCY_CD = #{salePlcyCd}

/* 휴대폰 목록 조회 PhoneMapper.listPhoneProdBasForFrontOneQuery */ SELECT A.PROD_ID, -- 상품 아이디 A.PROD_CTG_ID, --상품분류아이디 (lte,3g) A.PROD_NM, --상품명 A.MAKR_CD, --제조사코드 A.RPRS_PRDT_ID, --대표모델ID A.SHOW_YN, --노출여부 A.SALE_YN, --판매여부 A.OFW_DATE, --출고일자 A.LIST_SHOW_TEXT, --목록노출텍스트 A.LIST_SHOW_OPTN, --목록노출옵션 A.SNTY_OS, --단말기OS A.SNTY_PROD_NM, --단말기명 A.SNTY_REL_MONTH, --출시월 A.SNTY_COLOR, --단말기색상 A.SNTY_MAKER, --단말기제조사/브랜드명 A.SNTY_MODEL_ID, --단말기모델번호 B.MNFCT_NM, --제조사명 A.MAKR_NM, --제조사명 중고폰에서만사용 A.INVENTORY_AMT, --중고폰 재고수량 A.SALE_PRICE, --중고폰 판매가격 A.PROD_GRADE, --종고폰 등급 A.SHAND_TYPE, --중고폰type 구분(중고폰,외산폰) A.RECOMMEND_RATE, --추천요금제 A.USED_WARRANTY, --중고폰 워런티 NVL(A.OFW_DATE,'') as ORDER_CRET_DT, PD_SALE.SALE_PLCY_CD, --정책코드 NVL(SESPLS_YN,'N') AS SESPLS_YN,--자급제여부 구분(Y,N) A.REP_RATE AS , --대표요금제 코드 A.AGRM_TRM_BASE -- 약정유형 ,( SELECT LISTAGG(SNTY.ATRIB_VAL_CD_1, ',') WITHIN GROUP(ORDER BY SNTY.PROD_ID) FROM NMCP_SNTY_PROD_BAS@DL_MCP SNTY WHERE SNTY.PROD_ID = A.PROD_ID AND NVL(SNTY.SDOUT_YN,'N') <> 'Y' GROUP BY SNTY.PROD_ID ) AS COLOR_CODES , ( SELECT CHA.OUT_UNIT_PRIC FROM CMN_HNDST_AMT CHA WHERE CHA.RPRS_PRDT_ID = A.RPRS_PRDT_ID AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN CHA.UNIT_PRIC_APPL_DTTM AND CHA.UNIT_PRIC_EXPR_DTTM AND ROWNUM = 1 ) AS OUT_UNIT_PRIC , ( SELECT IN_UNIT_PRIC FROM CMN_MNFCT_AMT CMN WHERE RPRS_PRDT_ID = A.RPRS_PRDT_ID AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN CMN.UNIT_PRIC_APPL_DTTM AND CMN.UNIT_PRIC_EXPR_DTTM AND ROWNUM = 1 ) AS IN_UNIT_PRIC FROM NMCP_PROD_BAS@DL_MCP A, ORG_MNFCT_MST B, NMCP_SNTY_PROD_BAS@DL_MCP SNTY, ( SELECT PRDT_ID, MAX(SALE_PLCY_CD) AS SALE_PLCY_CD FROM MSP_SALE_PRDT_MST WHERE SALE_PLCY_CD IN
#{prdt.salePlcyCd}
GROUP BY PRDT_ID ) PD_SALE WHERE A.SHOW_YN ='Y' AND A.RPRS_PRDT_ID = PD_SALE.PRDT_ID AND A.SALE_YN ='Y' AND A.MAKR_CD = B.MNFCT_ID
AND A.SHAND_YN = #{shandYn}
AND A.PROD_ID = SNTY.PROD_ID
AND A.PROD_CTG_ID = #{prodCtgId}
AND SNTY.RPRS_PRDT_YN = 'Y'
AND A.MAKR_CD = #{makrCd}
AND A.PROD_ID = T1.PROD_ID
AND A.PROD_TYPE IN('01','04','05','06')
AND PROD_TYPE =#{prodType}
AND NVL(SESPLS_YN,'N') = #{sesplsYn}
AND A.PROD_ID = #{prodId}
